mapper.select:
SELECT utl.id, utl.uid, u.nickname, u.phone, utl.team_level_id AS teamLevelId, stl.name AS teamLevelName, utl.grade, CASE WHEN utl.status THEN 1 ELSE 0 END AS status, utl.mark, utl.create_time AS createTime FROM eb_user_team_level utl LEFT JOIN eb_user u ON u.uid = utl.uid LEFT JOIN eb_system_team_level stl ON stl.id = utl.team_level_id WHERE utl.is_del = 0
AND ( utl.uid = #{keywords} OR u.nickname LIKE CONCAT('%', #{keywords}, '%') OR u.phone LIKE CONCAT('%', #{keywords}, '%') )
AND utl.team_level_id = #{teamLevelId}
AND CASE WHEN utl.status THEN 1 ELSE 0 END = #{status}
ORDER BY utl.id DESC
